import { isValidNumber } from './is-valid-number.js';
import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { charsFontWidth12pixelsSize400Map } from '../../../../text-ellipsis/chars-font-width-map.js';
import { truncateString } from '../../../../text-ellipsis/truncate-string.js';
import { calculateTotalWidth400 } from '../../../utils/width-calculation.js';

/**
 * @param text - The text to display
 * @param availableWidth - Maximum available width in pixels
 * @param truncationMode - The truncation mode to use
 * @returns The truncated text if necessary, or original text if it fits
 */
export const getDisplayText = (
  text: string,
  availableWidth: number | undefined,
  truncationMode: TruncationMode,
): string => {
  if (!text || text.trim() === '') {
    return text;
  }

  if (!isValidNumber(availableWidth)) {
    return text;
  }

  const textWidth = calculateTotalWidth400(text);
  if (textWidth <= availableWidth) {
    return text;
  }

  return truncateString(
    text,
    availableWidth,
    charsFontWidth12pixelsSize400Map,
    truncationMode,
  );
};
